#include <stdio.h>
#include <string.h>

#define N 3
#define QUANTUM 2

int main(void) {
    int burst[] = {4, 2, 6};
    int remaining[N];
    int completion[N];
    memcpy(remaining, burst, sizeof(burst));

    int time = 0, done = 0;
    while (done < N) {
        for (int i = 0; i < N; i++) {
            if (remaining[i] > 0) {
                int run = (remaining[i] < QUANTUM) ? remaining[i] : QUANTUM;
                time += run;
                remaining[i] -= run;
                if (remaining[i] == 0) {
                    completion[i] = time;
                    done++;
                }
            }
        }
    }

    float total_wait = 0, total_ta = 0;
    for (int i = 0; i < N; i++) {
        int ta = completion[i];
        int wait = ta - burst[i];
        total_wait += wait;
        total_ta += ta;
    }

    printf("Average waiting time: %.2f\n", total_wait / N);
    printf("Average turnaround time: %.2f\n", total_ta / N);
    return 0;
}

